// ---------------------------------------------------------------------------
// In-memory LRU cache for verified tokens to avoid repeated crypto operations
// ---------------------------------------------------------------------------
class TokenCache {
  constructor(maxSize = 50000, sweepIntervalMs = 60_000) {
    this.maxSize = maxSize;
    this.cache = new Map(); // token-hash -> { payload, expiresAt }
    // Periodic sweep to remove expired entries and keep memory bounded
    this._sweepInterval = setInterval(() => this._sweep(), sweepIntervalMs);
    if (this._sweepInterval.unref) this._sweepInterval.unref();
  }

  _hash(token) {
    // Fast hash – avoids storing raw tokens in memory
    return crypto.createHash('sha256').update(token).digest('base64');
  }

  get(token) {
    const key = this._hash(token);
    const entry = this.cache.get(key);
    if (!entry) return null;
    if (Date.now() >= entry.expiresAt) {
      this.cache.delete(key);
      return null;
    }
    // Move to end (most-recently used) – Map preserves insertion order
    this.cache.delete(key);
    this.cache.set(key, entry);
    return entry.payload;
  }

  set(token, payload) {
    const key = this._hash(token);
    // Evict oldest entries if at capacity
    if (this.cache.size >= this.maxSize) {
      const firstKey = this.cache.keys().next().value;
      this.cache.delete(firstKey);
    }
    this.cache.set(key, {
      payload,
      expiresAt: (payload.exp || 0) * 1000, // jwt exp is in seconds
    });
  }

  // Bulk-invalidate tokens for a specific user (e.g. on password change)
  invalidateUser(userId) {
    for (const [key, entry] of this.cache) {
      if (entry.payload && entry.payload.sub === userId) {
        this.cache.delete(key);
      }
    }
  }

  _sweep() {
    const now = Date.now();
    for (const [key, entry] of this.cache) {
      if (now >= entry.expiresAt) {
        this.cache.delete(key);
      }
    }
  }

  destroy() {
    clearInterval(this._sweepInterval);
    this.cache.clear();
  }
}

const tokenCache = new TokenCache();

// ---------------------------------------------------------------------------
// Token generation helpers
