function generateAccessToken(user) {
  const payload = {
    sub: user.id,
    email: user.email,
    roles: user.roles || [],
    // Embed a token-generation timestamp so we can do "issued-after" checks
    iat: Math.floor(Date.now() / 1000),
  };
  return jwt.sign(payload, config.accessTokenSecret, {
    algorithm: config.algorithm,
    expiresIn: config.accessTokenExpiry,
    issuer: config.issuer,
    audience: config.audience,
  });
}

function generateRefreshToken(user) {
  const payload = {
    sub: user.id,
    type: 'refresh',
    iat: Math.floor(Date.now() / 1000),
  };
  return jwt.sign(payload, config.refreshTokenSecret, {
    algorithm: config.algorithm,
    expiresIn: config.refreshTokenExpiry,
    issuer: config.issuer,
    audience: config.audience,
  });
}

// ---------------------------------------------------------------------------
// Lightweight "issued-after" map – instead of a blocklist, store a per-user
// timestamp. Any token issued before this timestamp is rejected.
// In production back this with Redis with pub/sub for multi-instance sync.
// ---------------------------------------------------------------------------
const userInvalidationMap = new Map(); // userId -> unix-timestamp (seconds)

function invalidateUserTokens(userId) {
  const now = Math.floor(Date.now() / 1000);
  userInvalidationMap.set(userId, now);
  tokenCache.invalidateUser(userId);
}

// ---------------------------------------------------------------------------
// Extract token from request (Authorization header, query, or cookie)
// ---------------------------------------------------------------------------
function extractToken(req) {
  // 1. Authorization: Bearer <token>
  const authHeader = req.headers.authorization;
  if (authHeader) {
    const parts = authHeader.split(' ');
    if (parts.length === 2 && /^Bearer$/i.test(parts[0])) {
      return parts[1];
    }
  }
  // 2. Query parameter (for WebSocket upgrades, etc.)
  if (req.query && req.query.token) {
    return req.query.token;
  }
  // 3. Cookie
  if (req.cookies && req.cookies.access_token) {
    return req.cookies.access_token;
  }
  return null;
}

