// Core authentication middleware
// ---------------------------------------------------------------------------
function authenticate(options = {}) {
  const {
    required = true,         // If false, unauthenticated requests pass through with req.user = null
    roles = null,            // Array of allowed roles, e.g. ['admin', 'editor']
    scopes = null,           // Array of required scopes
  } = options;

  return function authMiddleware(req, res, next) {
    const token = extractToken(req);

    if (!token) {
      if (!required) {
        req.user = null;
        return next();
      }
      return res.status(401).json({
        error: 'authentication_required',
        message: 'Missing authentication token',
      });
    }

    // --- Fast path: check cache first to avoid jwt.verify crypto ---
    let payload = tokenCache.get(token);

    if (payload) {
      // Validate against user-level invalidation (password change, logout-all)
      const invalidatedAt = userInvalidationMap.get(payload.sub);
      if (invalidatedAt && payload.iat && payload.iat < invalidatedAt) {
        return res.status(401).json({
          error: 'token_revoked',
          message: 'Token has been revoked. Please re-authenticate.',
        });
      }

      // Attach user and proceed
      req.user = buildUserFromPayload(payload);
      return authorise(req, res, next, roles, scopes);
    }

    // --- Slow path: full cryptographic verification ---
    try {
      payload = jwt.verify(token, config.accessTokenSecret, {
        algorithms: [config.algorithm],
        issuer: config.issuer,
        audience: config.audience,
        clockTolerance: 5, // seconds of tolerance for clock skew
      });
    } catch (err) {
      const response = mapJwtError(err);
      return res.status(response.status).json(response.body);
    }

    // Check user-level invalidation
    const invalidatedAt = userInvalidationMap.get(payload.sub);
    if (invalidatedAt && payload.iat && payload.iat < invalidatedAt) {
      return res.status(401).json({
        error: 'token_revoked',
        message: 'Token has been revoked. Please re-authenticate.',
      });
    }

    // Cache the verified payload for subsequent requests with the same token
    tokenCache.set(token, payload);

    req.user = buildUserFromPayload(payload);
    return authorise(req, res, next, roles, scopes);
  };
}

function buildUserFromPayload(payload) {
  return {
    id: payload.sub,
    email: payload.email,
    roles: payload.roles || [],
    scopes: payload.scopes || [],
    tokenIssuedAt: payload.iat,
  };
}

function authorise(req, res, next, requiredRoles, requiredScopes) {
  // Role-based access control
  if (requiredRoles && requiredRoles.length > 0) {
    const userRoles = req.user.roles || [];
    const hasRole = requiredRoles.some((role) => userRoles.includes(role));
    if (!hasRole) {
      return res.status(403).json({
        error: 'insufficient_role',
        message: `Required role(s): ${requiredRoles.join(', ')}`,
      });
    }
  }

  // Scope-based access control
  if (requiredScopes && requiredScopes.length > 0) {
    const userScopes = req.user.scopes || [];
    const hasAllScopes = requiredScopes.every((scope) => userScopes.includes(scope));
    if (!hasAllScopes) {
      return res.status(403).json({
        error: 'insufficient_scope',
        message: `Required scope(s): ${requiredScopes.join(', ')}`,
      });
    }
  }

  return next();
}

function mapJwtError(err) {
  if (err.name === 'TokenExpiredError') {
    return {
      status: 401,
      body: {
        error: 'token_expired',
        message: 'Access token has expired',
        expiredAt: err.expiredAt,
      },
    };
  }
  if (err.name === 'JsonWebTokenError') {
    return {
      status: 401,
      body: {
        error: 'invalid_token',
        message: 'Token signature is invalid',
      },
    };
  }
  if (err.name === 'NotBeforeError') {
    return {
      status: 401,
      body: {
        error: 'token_not_active',
        message: 'Token is not yet active',
      },
    };
  }
  return {
    status: 401,
    body: {
      error: 'authentication_failed',
      message: 'Authentication failed',
    },
  };
}

